var val = Services.getValue(AmountAlreadyPaid.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err)
{	Services.setValue( AmountAlreadyPaid.dataBinding, WPU.formatToTwoDP(val));
}
return err;

