function DefaultCurrency324() {}
DefaultCurrency324.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency324.tabIndex = -1;
DefaultCurrency324.maxLength = 1;
DefaultCurrency324.isReadOnly = function(){return true;}
DefaultCurrency324.isTemporary = function(){return true;}
DefaultCurrency324.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency324.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
